import { cursor } from './cursor';
import { gamePaused } from './game';
import { editableCells } from './grid';
import { derived } from 'svelte/store';

export const keyboardDisabled = derived(
	[cursor, editableCells, gamePaused],
	([$cursor, $editableCells, $gamePaused]) => {
		return ($cursor.x === null && $cursor.y === null) || !$editableCells.has(`${$cursor.x},${$cursor.y}`) || $gamePaused;
	},
	false,
);
